mapper.select:
/* com.shop.mapper.partner.selectPartnerList */ SELECT ID AS id, UPPER_PARTNER_ID AS upperPartnerId, FILE_ID AS fileId, LOGIS_ID AS logisId, PARTNER_NM AS partnerNm, SHORT_NM AS shortNm, PARTNER_TEL_NO AS partnerTelNo, REP_NM AS repNm, REP_TEL_NO AS repTelNo, COMP_NO AS compNo, DETAIL_INFO AS detailInfo, PARTNER_EMAIL AS partnerEmail, CRE_USER AS creUser, CRE_TM AS creTm, UPD_USER AS updUser, UPD_TM AS updTm, DEL_YN AS deleteYn, ADD_TIME AS addTime, ETC_ACC_CNTN AS etcAccCntn, MISONG_YN AS misongYn, SIZE_INFO AS sizeInfo, ORDER_SHORT_NM AS orderShortNm FROM TB_PARTNER WHERE DEL_YN = 'N'
AND LOGIS_ID = #{logisId}
ORDER BY PARTNER_NM ASC;

/* com.shop.mapper.partner.selectPartnerListForSearching */ SELECT ID AS id, UPPER_PARTNER_ID AS upperPartnerId, FILE_ID AS fileId, LOGIS_ID AS logisId, PARTNER_NM AS partnerNm, SHORT_NM AS shortNm, PARTNER_TEL_NO AS partnerTelNo, REP_NM AS repNm, REP_TEL_NO AS repTelNo, COMP_NO AS compNo, DETAIL_INFO AS detailInfo, PARTNER_EMAIL AS partnerEmail, CRE_USER AS creUser, CRE_TM AS creTm, UPD_USER AS updUser, UPD_TM AS updTm, DEL_YN AS deleteYn, ADD_TIME AS addTime, ETC_ACC_CNTN AS etcAccCntn, MISONG_YN AS misongYn, SIZE_INFO AS sizeInfo, ORDER_SHORT_NM AS orderShortNm FROM TB_PARTNER P WHERE P.DEL_YN = 'N'
AND P.PARTNER_NM LIKE CONCAT('%', #{partnerNm}, '%')
ORDER BY PARTNER_NM ASC;

/* com.shop.mapper.partner.selectPartnerByCompNo */
SELECT 
FROM TB_PARTNER AS TP
WHERE TP.COMP_NO = #{compNo}
AND DEL_YN = 'N'

SELECT (NOW() + (COALESCE(ADD_TIME, 6) || ' hour')::INTERVAL)::DATE
  FROM TB_PARTNER
 WHERE ID = #{partnerId}

