    , ORDER_SHORT_NM

)
VALUES
(

    #{upperPartnerId}


    , #{fileId}


    , #{logisId}

    , #{partnerNm}

    , #{shortNm}

    , #{partnerTelNo}
    , #{repNm}
    , #{repTelNo}
    , #{compNo}

    , #{detailInfo}


