)

mapper.update:
/* com.shop.mapper.partner.updatePartner */
UPDATE TB_PARTNER
SET UPD_TM   = NOW(),
    UPD_USER = #{updUser}

    , UPPER_PARTNER_ID = #{upperPartnerId}


    , LOGIS_ID = #{logisId}


    , FILE_ID = #{fileId}


    , PARTNER_NM = #{partnerNm}


    , PARTNER_ENG_NM = #{partnerEngNm}


    , SHORT_NM = #{shortNm}


    , PARTNER_TEL_NO = #{partnerTelNo}


    , REP_NM = #{repNm}


    , REP_TEL_NO = #{repTelNo}


    , COMP_NO = #{compNo}


    , PARTNER_EMAIL = #{partnerEmail}


    , ADD_TIME = #{addTime}


    , DETAIL_INFO = #{detailInfo}


    , MISONG_YN = #{misongYn}


    , SIZE_INFO = #{sizeInfo}


    , ORDER_SHORT_NM = #{orderShortNm}


    , COMP_PRN_CD = #{compPrnCd}


    , SAMPLE_PRN_YN = #{samplePrnYn}


    , FAC_GB1_CNTN = #{facGb1Cntn}


    , FAC_GB2_CNTN = #{facGb2Cntn}


    , SEL_GB1_CNTN = #{selGb1Cntn}


    , SEL_GB2_CNTN = #{selGb2Cntn}


    , GUBUN_INFO = #{gubunInfo}


    , SETTL_CD = #{settlCd}


    , COMP_INFO = #{compInfo}


    , PARTNER_ADDR = #{partnerAddr}


    , PARTNER_ADDR_ETC = #{partnerAddrEtc}


    , SNS_TYPE = #{snsType}


    , SNS_ID = #{snsId}


    , ETC_CNTN = #{etcCntn}


    , ETC_ACC_CNTN = #{etcAccCntn}


    , FACSETTLE_ETC_CNTN = #{facsettleEtcCntn}


    , ORDER_SEQ = #{orderSeq}

WHERE ID = #{id}

/* com.shop.mapper.partner.deletePartner */
UPDATE TB_PARTNER
    SET DEL_YN = 'Y'
WHERE ID = #{id}
